+// TestAutoCommit_InitializeSession_EmptyRepo verifies that InitializeSession
+// returns ErrEmptyRepository when called on a repo with no commits.
+// Uses t.Chdir (process-global state), so cannot use t.Parallel().
+func TestAutoCommit_InitializeSession_EmptyRepo(t *testing.T) {
+	dir := t.TempDir()
+	_, err := git.PlainInit(dir, false)
+	if err != nil {
+		t.Fatalf("failed to init repo: %v", err)
+	}
+
+	t.Chdir(dir)
+
+	s := &AutoCommitStrategy{}
+	err = s.InitializeSession("test-session", agent.AgentTypeClaudeCode, "/tmp/transcript.jsonl", "hello")
+	if err == nil {
+		t.Fatal("InitializeSession() should return error for empty repo")
+	}
+	if !errors.Is(err, ErrEmptyRepository) {
+		t.Errorf("InitializeSession() error = %v, want ErrEmptyRepository", err)
+	}
+}
diff --git a/cmd/entire/cli/strategy/common.go b/cmd/entire/cli/strategy/common.go
index 211c420..163a48d 100644
--- a/cmd/entire/cli/strategy/common.go
+++ b/cmd/entire/cli/strategy/common.go
@@ -38,6 +38,14 @@ const (
 // Each package needs its own package-scoped sentinel for git log iteration patterns.
 var errStop = errors.New("stop iteration")

+// IsEmptyRepository returns true if the repository has no commits yet.
+// This is detected by checking if HEAD exists — a freshly git-init'd repo
+// has no HEAD reference until the first commit is created.
+func IsEmptyRepository(repo *git.Repository) bool {
+	_, err := repo.Head()
+	return errors.Is(err, plumbing.ErrReferenceNotFound)
+}
+
 // IsAncestorOf checks if commit is an ancestor of (or equal to) target.
 // Returns true if target can reach commit by following parent links.
 // Limits search to 1000 commits to avoid excessive traversal.
